/** Create an ErrorEnvelope with auto-generated timestamp and traceId. */
export function createErrorEnvelope(
  error: string,
  message: string,
  details?: Record<string, unknown>,
): ErrorEnvelope {
  // Extract context for error guidance from details
  const context: Record<string, string | number | boolean | undefined> = {};
  if (details) {
    for (const [key, value] of Object.entries(details)) {
      if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") {
        context[key] = value;
      }
    }
  }

  // Get error recovery guidance
  const guidance = getErrorGuidance(error, context);

  // Merge guidance into details
  const enhancedDetails = {
    ...details,
    guidance: {
      suggestions: guidance.suggestions,
      exampleCommands: guidance.exampleCommands,
      documentationLinks: guidance.documentationLinks,
    },
  };

  // Derive a top-level `remediation` from the first guidance suggestion
  // for codes the catalog knows about. Unknown codes get the generic
  // "Check the error message for details" string which is not useful as a
  // remediation hint -- only surface it when the catalog has a curated
  // entry (i.e. guidance has more than just the generic fallback).
  const isCuratedGuidance =
    guidance.suggestions.length > 0 &&
    guidance.suggestions[0] !== "Check the error message for details";
  const remediation = isCuratedGuidance ? guidance.suggestions[0] : undefined;

  return {
    error,
    message,
    timestamp: new Date().toISOString(),
    traceId: generateTraceId(),
    ...(remediation !== undefined ? { remediation } : {}),
    details: enhancedDetails,
  };
}

