/**
 * Look up a cached summary by `(nodeId, source)`. On HIT, the entry's `seen`
 * counter is bumped (so it survives pruning) and the payload is returned. On
 * MISS, returns `null` — the caller summarises via the LLM and then calls
 * {@link set}.
 */
get(nodeId: string, source: string): CachedSummary | null {
  const key = summaryCacheKey(nodeId, source);
  const entry = this.file.entries[key];
  if (entry === undefined) return null;
  // Touch: bump last-seen so a still-relevant entry isn't pruned.
  entry.seen = this.file.next++;
  this.dirty = true;
  return { summary: entry.summary, tags: entry.tags };
}

/**
 * Stable content-hash cache key for a node: `sha256(id + ':' + source)`.
 * Exported + pure for unit testing. The same `(id, source)` always yields the
 * same key; any change to either flips it.
 */
export function summaryCacheKey(nodeId: string, source: string): string {
  return createHash('sha256').update(`${nodeId}:${source}`).digest('hex');
}

source_snippets.TheForge.src.services.routes.graph.KgLru:
get(key: string): KgLruEntry | undefined {
  const entry = this._cache.get(key);
  if (entry === undefined) return undefined;
  // Refresh recency: re-inserting moves the key to the tail (MRU position).
  this._cache.delete(key);
  this._cache.set(key, entry);
  return entry;
}

set(key: string, entry: KgLruEntry): void {
  if (this._cache.has(key)) this._cache.delete(key);
  this._cache.set(key, entry);
  // Evict the LRU (head) entry when over capacity.
  while (this._cache.size > this._maxEntries) {
    const oldest = this._cache.keys().next().value;
    if (oldest === undefined) break;
    this._cache.delete(oldest);
  }
}

