/**
 * Returns the `Authorization` header record to include in every outbound
 * cross-service fetch request.
 *
 * - Dev mode: returns `{}` (empty) — services accept any request on localhost.
 * - Prod mode: returns `{ Authorization: 'Bearer <token>' }`.
 *
 * Also supports the alternate `X-Forge-Service-Token` header for upstream
 * proxies that reserve the `Authorization` header; pass `useAlternate: true`
 * to get that form instead.
 *
 * @param useAlternate When true, returns the alternate header instead of
 *   `Authorization`. Default: false.
 */
export function authHeaders(useAlternate = false): Record<string, string> {
  if (!TOKEN) return {};
  if (useAlternate) {
    return { 'X-Forge-Service-Token': TOKEN };
  }
  return { Authorization: `Bearer ${TOKEN}` };
}

