export async function validateLive(req: Request, res: Response) {
  const { content, type } = req.body;

  if (!content || !type) {
    return res.status(400).json(createErrorEnvelope('invalid_request', 'Missing content or type'));
  }

  if (type === 'openapi' || type === 'yaml') {
    try {
      yamlParse(content);
      // For a true "Schema Lab", OpenAPI validation requires a bit more (e.g., swagger-cli). 
      // Basic YAML parsing covers syntax. Compliance is handled in Step 5.
      return res.json({ valid: true, errors: [] });
    } catch (err) {
      return res.json({ valid: false, errors: [(err as Error).message] });
    }
  }

  const tempDir = join(tmpdir(), `forge-validation-${randomUUID()}`);

  try {
    await mkdir(tempDir, { recursive: true });

    if (type === 'prisma') {
      const schemaPath = join(tempDir, 'schema.prisma');
      await writeFile(schemaPath, content, 'utf8');

      try {
        await execAsync(`npx prisma validate --schema="${schemaPath}"`, {
          env: { ...process.env, DATABASE_URL: 'postgresql://fake' }
        });
        return res.json({ valid: true, errors: [] });
      } catch (err) {
        // Extract useful part of Prisma error
        const e = err as Record<string, string>;
        const stderr = e['stderr'] ?? e['stdout'] ?? (err as Error).message ?? '';
        const cleanError = stderr.replace(/┌[\s\S]*?└[─]+┘/g, '').trim(); // Remove update banner
        return res.json({ valid: false, errors: [cleanError] });
      }
    }

    // Unknown type — skip validation rather than surfacing an error in the UI
    return res.json({ valid: null, errors: [] });

  } finally {
    try {
      await rm(tempDir, { recursive: true, force: true });
    } catch {
      // ignore
    }
  }
}

