async function request<T>(
  input: string,
  init: RequestInit | undefined,
  options?: HttpOptions,
): Promise<T> {
  // Preserve byte-identical `fetch` call shapes: when neither a default init
  // nor a caller `init` is present, invoke `fetch(url)` with no second arg
  // (matching the prior inline GET helpers, which tests assert on).
  const merged: RequestInit | undefined =
    init || options?.init ? { ...init, ...options?.init } : undefined;
  const res = merged === undefined ? await fetch(input) : await fetch(input, merged);
  if (!res.ok) {
    throw await (options?.parseError ?? defaultParseError)(res);
  }
  return res.json() as Promise<T>;
}

